{
  "business_expectations": [
    {
      "expectation_id": "回答明确指出轻症可以进行多次赔付",
      "description": "针对用户问题‘是不是能赔多次’，答案需明确肯定轻症可进行多次赔付。",
      "acceptance_criteria": "答案中包含如“轻症可以赔付多次”或等效表述。"
    },
    {
      "expectation_id": "回答提供每次赔付金额比例范围",
      "description": "回答需给出轻症每次赔付金额相对于基本保险金额的比例，例如20%至30%。",
      "acceptance_criteria": "答案中包含类似“20%至30%”的比例数值。"
    },
    {
      "expectation_id": "回答提及赔付次数上限",
      "description": "回答需说明轻症赔付可能有次数限制，并给出常见次数示例（如3次或5次）。",
      "acceptance_criteria": "答案中提到次数上限或列出如‘3次或5次’的示例。"
    },
    {
      "expectation_id": "回答提及轻症赔付间隔期",
      "description": "回答需提及两次轻症赔付之间可能存在间隔期（如90天或180天）。",
      "acceptance_criteria": "答案中提及‘间隔期’或其同义词。"
    },
    {
      "expectation_id": "回答引导用户查阅个人合同（免责/风险控制）",
      "description": "回答需提醒用户实际赔付规则以合同为准，并建议查阅合同条款，以降低误解答复为绝对承诺的风险。",
      "acceptance_criteria": "答案中包含类似‘建议查阅您的保险合同条款’或等效提示。"
    },
    {
      "expectation_id": "回答与参考答案无矛盾且不添加虚假信息",
      "description": "答案中的所有事实陈述应与参考答案一致，不得包含错误或与常识相悖的信息。",
      "acceptance_criteria": "经人工/机器比对，答案中无任何与参考答案抵触或明显失实之处。"
    }
  ],
  "fulfillment_assessments": [
